namespace ThemeEngine.Generators;

public class KittyGenerator : IGenerator
{
    public string Name => "Kitty";
    public string OutputPath => ".config/kitty/kitty.conf";

    public string Generate(Theme theme, string wallpapersDir)
    {
        var c = theme.Colors;
        var f = theme.Font;

        return $$"""
# Auto-generated by ThemeEngine — do not edit manually
# Theme: {{theme.Name}}

# Font
font_family {{f.Family}}
font_size 12.0

# Colors
foreground {{c.Text}}
background {{c.Bg0}}
selection_foreground {{c.Bg0}}
selection_background {{c.Border}}
cursor {{c.Border}}
cursor_text_color {{c.Bg0}}
url_color {{c.Accent1}}

# Window
background_opacity 0.92
window_padding_width 8
window_margin_width 0
hide_window_decorations yes
confirm_os_window_close 0

# Tab bar
active_tab_foreground {{c.Accent1}}
active_tab_background {{c.Bg1}}
active_tab_font_style bold
inactive_tab_foreground {{c.TextDim}}
inactive_tab_background {{c.Bg0}}
tab_bar_edge bottom
tab_bar_style powerline
tab_powerline_style slanted

# Terminal bell
enable_audio_bell no
visual_bell_duration 0

# ANSI colors
# black
color0 {{c.Bg0}}
color8 {{c.Inactive}}

# red
color1 {{c.Red}}
color9 #A83000

# green
color2 {{c.Green}}
color10 #6A8A57

# yellow
color3 {{c.Accent1}}
color11 {{c.Border}}

# blue
color4 {{c.Blue}}
color12 #5A7A8A

# magenta
color5 {{c.Accent2}}
color13 #C8843A

# cyan
color6 #6A8A7A
color14 #7A9A8A

# white
color7 {{c.Text}}
color15 #F0E0CC
""";
    }
}
